module.exports = "<!-- ── Barre de recherche ─────────────────────────────────────── -->\n<div class=\"ds-search-bar__field\">\n  <svg class=\"ds-search-bar__icon\" width=\"24\" height=\"24\" viewBox=\"0 0 24 24\" fill=\"none\"\n       xmlns=\"http://www.w3.org/2000/svg\" aria-hidden=\"true\">\n    <circle cx=\"11\" cy=\"11\" r=\"7\" stroke=\"currentColor\" stroke-width=\"1.5\"/>\n    <path d=\"M16.5 16.5L21 21\" stroke=\"currentColor\" stroke-width=\"1.5\" stroke-linecap=\"round\"/>\n  </svg>\n\n  <input\n    class=\"ds-search-bar__input\"\n    type=\"search\"\n    [placeholder]=\"placeholder()\"\n    [(ngModel)]=\"value\"\n    (focus)=\"onInputFocus()\"\n    (keydown)=\"onKeydown($event)\"\n    aria-label=\"Search\"\n    [attr.aria-expanded]=\"flyoutOpen()\"\n    aria-haspopup=\"listbox\"\n  />\n</div>\n\n<ds-button type=\"primary\" (click)=\"onSearch()\">{{ buttonLabel() }}</ds-button>\n\n<!-- ── Flyout — recherches récentes ──────────────────────────── -->\n@if (flyoutOpen() && recentSearches().length > 0) {\n  <div class=\"ds-search-flyout\" role=\"listbox\" aria-label=\"Recherches récentes\">\n\n    <!-- Section RECENT -->\n    <div class=\"ds-search-flyout__section\">\n      <p class=\"ds-search-flyout__section-label\">RECENT</p>\n\n      <ul class=\"ds-search-flyout__list\">\n        @for (item of recentSearches(); track item.label) {\n          <li class=\"ds-search-flyout__item\"\n              role=\"option\"\n              (click)=\"selectRecent(item)\"\n              (keydown.enter)=\"selectRecent(item)\"\n              tabindex=\"0\">\n            <div class=\"ds-search-flyout__item-left\">\n              <!-- Icône horloge / historique -->\n              <svg class=\"ds-search-flyout__item-icon\" width=\"16\" height=\"16\" viewBox=\"0 0 16 16\"\n                   fill=\"none\" xmlns=\"http://www.w3.org/2000/svg\" aria-hidden=\"true\">\n                <circle cx=\"8\" cy=\"8\" r=\"5.5\" stroke=\"currentColor\" stroke-width=\"1.25\"/>\n                <path d=\"M8 5.5V8.5L9.5 9.5\" stroke=\"currentColor\" stroke-width=\"1.25\"\n                      stroke-linecap=\"round\" stroke-linejoin=\"round\"/>\n              </svg>\n              <span class=\"ds-search-flyout__item-label\">{{ item.label }}</span>\n            </div>\n\n            <ds-badge\n              [label]=\"item.badgeLabel\"\n              [status]=\"item.badgeStatus\"\n              [variant]=\"'light'\"\n              [size]=\"'s'\"\n            />\n          </li>\n        }\n      </ul>\n    </div>\n\n    <!-- Séparateur -->\n    <div class=\"ds-search-flyout__divider\" aria-hidden=\"true\"></div>\n\n    <!-- Footer : Advanced search -->\n    <div class=\"ds-search-flyout__footer\">\n      <ds-link\n        [href]=\"advancedSearchHref()\"\n        size=\"s\"\n        weight=\"semi-bold\"\n        tone=\"default\"\n      >\n        Advanced search\n        <svg slot=\"icon-right\" width=\"16\" height=\"16\" viewBox=\"0 0 16 16\" fill=\"none\"\n             xmlns=\"http://www.w3.org/2000/svg\" aria-hidden=\"true\">\n          <path d=\"M3 8h10M9 4l4 4-4 4\"\n                stroke=\"currentColor\" stroke-width=\"1.5\"\n                stroke-linecap=\"round\" stroke-linejoin=\"round\"/>\n        </svg>\n      </ds-link>\n    </div>\n\n  </div>\n}\n";

